import React, { createContext, useContext, useMemo, useState } from 'react';

const LanguageContext = createContext();

const translations = {
  en: {
    catalog: 'Catalog',
    forum: 'Forum',
    search: 'Search',
    settings: 'Settings',
    language: 'Language',
    save: 'Save',
    adminPanel: 'Admin Panel',
    users: 'Users',
    contentUpload: 'Content Upload',
    analytics: 'Analytics',
    contentManagement: 'Content Management',
    commentsModeration: 'Comments Moderation'
  },
  uz: {
    catalog: 'Katalog',
    forum: 'Forum',
    search: 'Qidirish',
    settings: 'Sozlamalar',
    language: 'Til',
    save: 'Saqlash',
    adminPanel: 'Admin Panel',
    users: 'Foydalanuvchilar',
    contentUpload: 'Kontent Yuklash',
    analytics: 'Analitika',
    contentManagement: 'Kontent Boshqaruvi',
    commentsModeration: 'Komment Moderatsiyasi'
  },
  ru: {
    catalog: 'ąÜą░čéą░ą╗ąŠą│',
    forum: 'ążąŠčĆčāą╝',
    search: 'ą¤ąŠąĖčüą║',
    settings: 'ąØą░čüčéčĆąŠą╣ą║ąĖ',
    language: 'ą»ąĘčŗą║',
    save: 'ąĪąŠčģčĆą░ąĮąĖčéčī',
    adminPanel: 'ąÉą┤ą╝ąĖąĮ-ą┐ą░ąĮąĄą╗čī',
    users: 'ą¤ąŠą╗čīąĘąŠą▓ą░čéąĄą╗ąĖ',
    contentUpload: 'ąŚą░ą│čĆčāąĘą║ą░ ą║ąŠąĮčéąĄąĮčéą░',
    analytics: 'ąÉąĮą░ą╗ąĖčéąĖą║ą░',
    contentManagement: 'ąŻą┐čĆą░ą▓ą╗ąĄąĮąĖąĄ ą║ąŠąĮčéąĄąĮčéąŠą╝',
    commentsModeration: 'ą£ąŠą┤ąĄčĆą░čåąĖčÅ ą║ąŠą╝ą╝ąĄąĮčéą░čĆąĖąĄą▓'
  }
};

export const LanguageProvider = ({ children }) => {
  const [language, setLanguage] = useState(localStorage.getItem('mangauz_language') || 'uz');

  const t = (key) => translations[language]?.[key] || translations.en[key] || key;

  const changeLanguage = (lang) => {
    setLanguage(lang);
    localStorage.setItem('mangauz_language', lang);
  };

  const value = useMemo(
    () => ({
      language,
      t,
      changeLanguage
    }),
    [language]
  );

  return <LanguageContext.Provider value={value}>{children}</LanguageContext.Provider>;
};

export const useLanguage = () => {
  const context = useContext(LanguageContext);
  if (!context) {
    throw new Error('useLanguage must be used within LanguageProvider');
  }
  return context;
};
